// Solution
function calculate(numbers, operation) {
  const operations = {
    add: (a, b) => a + b,
    subtract: (a, b) => a - b,
    multiply: (a, b) => a * b,
    divide: (a, b) => b !== 0 ? a / b : 'Error: Division by zero'
  };
  return operations[operation](numbers[0], numbers[1]);
}

solutions.python:
class Calculator:
  def calculate(self, numbers, operation):
    operations = {
      'add': lambda a, b: a + b,
      'subtract': lambda a, b: a - b,
      'multiply': lambda a, b: a * b,
      'divide': lambda a, b: b != 0 and a / b or 'Error: Division by zero'
    }
    return operations[operation](numbers[0], numbers[1])


import sys
if __name__ == '__main__':
  for line in sys.stdin:
    numbers, operation = line.strip().split(', ')
    numbers = list(map(float, numbers.split(', ')))
    print(Calculator().calculate(numbers, operation))
